106	async function mockEfficacy(
107		page: import('@playwright/test').Page,
108		opts: {
109			compareFn?: (req: Record<string, unknown>) => Record<string, unknown>;
110			rows?: typeof EFFICACY_ROWS;
111		} = {}
112	) {
113		await page.route('/graphql', async (route) => {
114			const body = route.request().postDataJSON() as {
115				query: string;
116				variables?: Record<string, unknown>;
117			};
118			if (body.query.includes('NodeInfo')) {
119				await route.fulfill({
120					status: 200,
121					contentType: 'application/json',
122					body: JSON.stringify({ data: { nodeInfo: NODE_INFO } })
123				});
124			} else if (body.query.includes('Projects')) {
125				await route.fulfill({
126					status: 200,
127					contentType: 'application/json',
128					body: JSON.stringify({ data: { projects: { edges: PROJECTS.map((p) => ({ node: p })) } } })
129				});
130			} else if (body.query.includes('EfficacyRows') || body.query.includes('efficacyRows')) {
131				await route.fulfill({
132					status: 200,
133					contentType: 'application/json',
134					body: JSON.stringify({ data: { efficacyRows: opts.rows ?? EFFICACY_ROWS } })
135				});
136			} else if (body.query.includes('EfficacyAttempts') || body.query.includes('efficacyAttempts')) {
137				await route.fulfill({
138					status: 200,
139					contentType: 'application/json',
140					body: JSON.stringify({ data: { efficacyAttempts: ATTEMPTS_DETAIL } })
141				});
142			} else if (
143				body.query.includes('ComparisonDispatch') ||
144				body.query.includes('comparisonDispatch')
145			) {
146				const result = opts.compareFn
147					? opts.compareFn(body.variables ?? {})
148					: { id: 'cmp-001', state: 'queued' };
149				await route.fulfill({
150					status: 200,
151					contentType: 'application/json',
152					body: JSON.stringify({ data: { comparisonDispatch: result } })
153				});
154			} else if (body.query.includes('Comparisons')) {
155				await route.fulfill({
156					status: 200,
157					contentType: 'application/json',
158					body: JSON.stringify({ data: { comparisons: [] } })
159				});
160			} else {
161				await route.continue();
162			}
163		});
164	}
