import { defineConfig } from '@playwright/test';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));

// The default Playwright harness boots the Go DDx server against a temp copy
// of e2e/fixtures/ so the API endpoints exercised by TC-008 (and other
// backend-dependent specs) return real data without reading the developer's
// $HOME or the repository's live .ddx/ state.

const CLI_PKG_DIR = path.resolve(__dirname, '../../..');
const FRONTEND_DIR = __dirname;
const FIXTURE_DIR = path.resolve(__dirname, 'e2e/fixtures');
const PORT = Number(process.env.DDX_E2E_PORT ?? 4174);
const BASE_URL = `https://127.0.0.1:${PORT}`;

// Build the SvelteKit frontend (so cli/internal/server/embed.go has assets to
// embed), copy the fixture workspace into a fresh temp dir, build the ddx
// binary from the cli module, and exec it from the temp dir. The temp dir has
// no .git so FindProjectRoot falls back to it, and tsnet is disabled so the
// harness has no Tailscale dependency.
const bootCommand = [
	`set -e`,
	`(cd "${FRONTEND_DIR}" && bun run build >&2)`,
	`TMP=$(mktemp -d -t ddx-e2e-XXXXXX)`,
	`cp -R "${FIXTURE_DIR}/." "$TMP/"`,
	`(cd "${CLI_PKG_DIR}" && go build -o "$TMP/ddx" .)`,
	`cd "$TMP"`,
	`exec ./ddx server --tsnet=false --addr=127.0.0.1 --port=${PORT}`
].join(' && ');

export default defineConfig({
	webServer: {
		command: `bash -c '${bootCommand}'`,
		url: `${BASE_URL}/api/health`,
		ignoreHTTPSErrors: true,
		reuseExistingServer: !process.env.CI,
		timeout: 180_000,
		stdout: 'pipe',
		stderr: 'pipe'
	},
	use: {
		baseURL: BASE_URL,
		ignoreHTTPSErrors: true
	},
	testMatch: ['**/*.e2e.{ts,js}', 'e2e/**/*.spec.ts']
});

import { expect, test } from '@playwright/test';

let NODE_INFO: { id: string; name: string };
let PROJECT_ID: string;
let PROJECTS: Array<{ id: string; name: string; path: string }>;

async function getFixtureIds(
	request: import('@playwright/test').APIRequestContext
): Promise<{ nodeId: string; projectId: string; nodeName: string; projectName: string; projectPath: string }> {
	const nodeResp = await request.post('/graphql', {
		data: { query: '{ nodeInfo { id name } }' }
	});
	const nodeBody = (await nodeResp.json()) as { data: { nodeInfo: { id: string; name: string } } };
	const projectsResp = await request.get('/api/projects');
	const projects = (await projectsResp.json()) as Array<{ id: string; name: string; path: string }>;
	const fixture = projects.find((p) => /(^|\/)ddx-e2e-/.test(p.path) || /^ddx-e2e-/.test(p.name));
	if (!fixture) {
		throw new Error(
			`fixture server has no ddx-e2e-* project registered (got: ${projects.map((p) => p.id).join(', ')})`
		);
	}
	return {
		nodeId: nodeBody.data.nodeInfo.id,
		projectId: fixture.id,
		nodeName: nodeBody.data.nodeInfo.name,
		projectName: fixture.name,
		projectPath: fixture.path
	};
}

test.beforeEach(async ({ request }) => {
	const ids = await getFixtureIds(request);
	NODE_INFO = { id: ids.nodeId, name: ids.nodeName };
	PROJECT_ID = ids.projectId;
